SELECT name, salary
FROM employees
WHERE salary > 50000 AND city = 'Pune';

SELECT department, COUNT(*)
FROM employees
GROUP BY department;

SELECT c.name, o.amount
FROM orders o
JOIN customers c ON o.customer_id = c.id;

CREATE TABLE products (
    id    INTEGER PRIMARY KEY,
    name  TEXT NOT NULL,
    price REAL CHECK (price >= 0)
);
